var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"마, 말도 안 돼! 총알이 제대로 먹히지도 않잖아!","JPN":"あ、あり得ない！　銃が効かない！","ENG":"N-no way! Bullets don't work on it!","TWN":"這…這怎麼可能！子彈竟然無法穿透她！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"자, 이제 그만 항복하세요.","JPN":"さあ、もう降伏してください。","ENG":"You should just surrender now.","TWN":"你們投降吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"으…… 으으으……","JPN":"う……うう……","ENG":"Aww... Aww...","TWN":"呃……呃呃……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"괴, 괴물…… 넌 괴물이야!","JPN":"ば、化け物……お前は化け物だ！","ENG":"M-monster... You're a monster!","TWN":"怪…有怪物……你是怪物！！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"으아아아!!!","JPN":"うわあああ！！","ENG":"Aaaah!","TWN":"啊啊啊！！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"후우……","JPN":"ふぅ……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"괜찮으세요?","JPN":"大丈夫ですか？","ENG":"Are you okay?","TWN":"你們沒事吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"우릴…… 도와준 건가?","JPN":"ワシらを……助けてくれたのか？","ENG":"Did you... do that to help us?","TWN":"你是……來幫我們的嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"고맙긴 하네만…… 보고도 믿기지 않는군.","JPN":"助かったが……とても信じられぬ光景じゃな。","ENG":"Thank you, but... that was unbelievable.","TWN":"雖然很感謝你……但又有點不敢置信。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"침식체가 나타나는 세상을 살아오면서, 침식체를 조종하는 인간은 한 번도 들어본 적이 없어.","JPN":"今まで侵食体が現れる世を生きてきたが、侵食体を操る人間なんて今まで一度も聞いたことがない。","ENG":"I'm used to seeing C.O.s, but I've never even heard of anyone who can command them like you.","TWN":"畢竟我活到現在，還沒看過可以控制侵蝕體的人。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"혹시 자네…… 정부에서 보내 준 카운터인가?","JPN":"もしかして君は……政府から送られたカウンターか？","ENG":"You... Are you a Counter from the government?","TWN":"還是……你是政府派來的制裁者嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런 건 아니지만, 여러분을 해치려는 건 아니니 믿어주세요.","JPN":"そうではないですけど、みなさんに危害を加えることはありませんので信じてください。","ENG":"No, but please trust me. I'm not here to hurt you.","TWN":"我不是，但我絕對沒有要傷害你們的意思，請相信我。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"허허…… 괜찮아. 나도 그 정도 변별력은 있다네.","JPN":"ハハハ……そのことなら大丈夫じゃ。ワシにもその程度の分別はあるんじゃよ。","ENG":"Hah hah... I know. Even I can see that.","TWN":"呵呵……放心吧！這點判斷力我還是有的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"여러분은…… 난민 분들이신가요?","JPN":"みなさんは……難民の方ですか？","ENG":"Are you... refugees?","TWN":"你們……都是難民嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그래, 반군을 피해 국경을 넘으려고 했지.","JPN":"ああ、反乱軍を避けて国境を越えようとしたんじゃ。","ENG":"Yes, we tried to cross the border to avoid the rebels.","TWN":"沒錯，我們原本是打算避開叛軍的耳目穿越國界的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"요새는 반군 활동이 다시 심해져서 브로커들도 손을 뗐어.","JPN":"最近反乱軍の動きが再び活発になってきて、ブローカーたちも手を引いてな。","ENG":"Recently, they've become prevalent again so that all brokers quit.","TWN":"最近叛軍又開始四處為非作歹，掮客也關門不敢做生意。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"거기에다 우리가 살던 마을도 침식지대가 되어 버렸으니까……. 별 수 없는 거지.","JPN":"それに、ワシたちが住んでいた村も侵食地帯になってしまって……仕方がないんじゃよ。","ENG":"But we couldn't stay in our village anymore. It became Corrupted. We had no choice.","TWN":"加上我們住的地方變成了侵蝕地區……實在是無計可施啊。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런 일이……","JPN":"そんなことが……","ENG":"That's terrible.","TWN":"怎麼會……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그렇다곤 해도, 누군가는 여기 남아서 떠나고 싶은 사람들을 도와야 해.","JPN":"とは言え、誰かはここに残り、国を出たい人たちを助けねばならぬ。","ENG":"Still, someone has to stay here and help others who want to leave.","TWN":"話雖如此，但還是要有人留下來幫助那些想離開的人。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"내 자식들은 그러지 못했으니까. 늙은이의 미련 같은 거지.","JPN":"ワシの子どもたちはそれができなかったからのう。年寄りの未練のようなものじゃ。","ENG":"My children couldn't leave even if they wanted to. Call it an old man's regret, if you will.","TWN":"不能犧牲我的孩子，所以只好由我這個老人家自己來囉。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……그랬군요.","JPN":"……そうだったんですね。","ENG":"... I see.","TWN":"……原來如此。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"여길 떠나려면 어쩔 수 없이 여길 거쳐야 하는 건가요?","JPN":"この国を出るためには、どうしてもここを通らなければならないのですか？","ENG":"Is this the only way out of the country?","TWN":"要離開的話，只能經過這裡嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"아무래도 그렇지.","JPN":"そうじゃな。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"이 고속도로 끝에 있는 국경선만 그나마 관리국 코앞이라……. 침식 현상에서 안전하다고 하거든.","JPN":"この高速道路の先にある国境線が、比較的管理局に近くてな……侵食現象に対して安全だと言われておる。","ENG":"The border at the end of this freeway is only near the Administration, it is said that it's safe from the Counterside effect.","TWN":"越過在這條高速公路盡頭的國界後就是管理局……那裡相對安全。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"혹시 자네도 그곳으로 향하고 있던 건가?","JPN":"もしかして君もそこに向かっていたのかい？","ENG":"Are you also heading there?","TWN":"你也是要去那裡嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"원래 있던 곳을 떠나, 뭘 해야 할지 모르게 됐을 때…… 다시 만나고 싶은 동생들이 떠올랐거든요.","JPN":"元いた場所を離れ、何をしたらいいかわからなくなった時……会いたかった人のことを思い出したのです。","ENG":"I left where I used to be, but I didn't know what to do. Then, I realized I wanted to reunite with my little sisters.","TWN":"離開原本的地方後，正當我不知該何去何從時……突然想到那群我很想再見一面的妹妹們。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"젊은 나이에 복잡한 사연이 있는 모양이구만…….","JPN":"若いのに複雑な事情があるようじゃな……","ENG":"You're young, but you seem to have gone through a lot already.","TWN":"看你年紀輕輕，似乎也經歷了不少事……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"괜찮다면 우리와 함께 가겠나?","JPN":"よかったらワシらと一緒に行くかい？","ENG":"Why don't you come with us?","TWN":"你願意的話，要和我們一起同行嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그래도 될까요?","JPN":"いいんですか？","ENG":"May I?","TWN":"可以嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"물론이지.","JPN":"もちろんじゃ。","ENG":"Of course.","TWN":"當然可以！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"하지만 하나 조건이 있네.","JPN":"じゃが、一つ条件がある。","ENG":"But under one condition.","TWN":"但我有個條件！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"조건…… 이요?","JPN":"条件……ですか？","ENG":"One... condition?","TWN":"條件……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CORRUPTED_NPC_LUCID_TAIL","text":{"KOREA":"킁!","JPN":"ガルン！","ENG":"Grr!","TWN":"呼嚕！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_16"},{"id":"L47_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"지금까지 고마웠어.","JPN":"今までありがとう。","ENG":"Thank you for your help so far.","TWN":"這段時間很謝謝你，"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"이곳에서 사람들 눈을 피해 얌전히 지내줘.","JPN":"ここで人々の目を避けて大人しく過ごしてね。","ENG":"Please stay here, away from people.","TWN":"以後你自己在這裡要小心，不要被人發現囉。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CORRUPTED_NPC_LUCID_TAIL","text":{"KOREA":"크르릉……","JPN":"ガルル……","ENG":"Grr...","TWN":"呼嚕嚕……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_07"},{"id":"L6_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"정말로 얌전히 앉아 있어. 침식체는 위험한 건데.","JPN":"本当に大人しく座ってる。侵食体は危険なはずなのに。","ENG":"Look how quietly it's sitting there. I thought all C.O.s are dangerous.","TWN":"這麼危險的侵蝕體竟然乖乖坐著欸！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"그러게. 꼭 강아지를 보는 것 같아.","JPN":"そうだね。まるで子犬みたい。","ENG":"I know. It's behaving like an obedient dog.","TWN":"感覺好像狗狗喔。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"부탁을 들어 줘서 고맙구만. 다른 사람들이 불안해해서 말이야.","JPN":"頼みを聞いてくれてすまないね。周りが不安がっているからのう。","ENG":"Thank you for agreeing to this. I just don't want to scare the others.","TWN":"謝謝你接受我的條件，因為我怕會嚇到其他人。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"……헤어지는 게 아쉽진 않나?","JPN":"……別れるのが寂しくはないのかね？","ENG":"... Don't you feel sad to say goodbye?","TWN":"……但就這樣分開你不難過嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"괜찮아요. 침식체가 사람들과 가까이 지내는 게 위험하다는 건 알고 있으니까요.","JPN":"大丈夫です。侵食体が人の近くにいると危険だということは知っていますから。","ENG":"It's okay. I know it's dangerous to keep C.O.s near people.","TWN":"沒關係，我明白人鬼殊途的道理，人類和侵蝕體是不能共存的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"そうか。","ENG":"I see.","TWN":"那就好。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그럼, 출발하겠네.","JPN":"じゃあ、出発するぞ。","ENG":"Then, let's go.","TWN":"那我們出發囉！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};